#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define WIDTH 800
#define HEIGHT 600

typedef struct { float x, y, z; } Vec;
typedef struct { Vec origin, direction; } Ray;
typedef struct { float t; Vec point; Vec normal; int hit; } Hit;

Vec vector_create(float x, float y, float z){ Vec v; v.x=x; v.y=y; v.z=z; return v; }
Vec vector_add(Vec a, Vec b){ return vector_create(a.x+b.x, a.y+b.y, a.z+b.z); }
Vec vector_subtract(Vec a, Vec b){ return vector_create(a.x-b.x, a.y-b.y, a.z-b.z); }
Vec vector_multiply(Vec a, float s){ return vector_create(a.x*s, a.y*s, a.z*s); }
float vector_dot(Vec a, Vec b){ return a.x*b.x + a.y*b.y + a.z*b.z; }
float vector_length(Vec a){ return sqrtf(a.x*a.x + a.y*a.y + a.z*a.z); }
Vec vector_normalize(Vec a){ float l=vector_length(a); return vector_create(a.x/l, a.y/l, a.z/l); }
Vec ray_at(Ray r, float t){ return vector_add(r.origin, vector_multiply(r.direction, t)); }

Hit sphere_intersect(Ray ray, Vec center, float radius){
    Hit h;
    Vec oc = vector_subtract(ray.origin, center);
    float a = vector_dot(ray.direction, ray.direction);
    float b = 2.0f * vector_dot(oc, ray.direction);
    float c = vector_dot(oc, oc) - radius*radius;
    float disc = b*b - 4.0f*a*c;
    if (disc < 0.0f){ h.hit=0; h.t=0; h.point=vector_create(0,0,0); h.normal=vector_create(0,0,0); return h; }
    double sq = sqrt((double)disc);
    float twoa = a + a;
    float t = (float)(((double)(-b) - sq) / (double)twoa);
    if (t < 0.001f){
        t = (float)(((double)(-b) + sq) / (double)twoa);
        if (t < 0.001f){ h.hit=0; h.t=0; h.point=vector_create(0,0,0); h.normal=vector_create(0,0,0); return h; }
    }
    h.t = t;
    h.point = ray_at(ray, t);
    h.normal = vector_normalize(vector_subtract(h.point, center));
    h.hit = 1;
    return h;
}

Vec sky_color(Ray ray){
    float t = (ray.direction.y + 1.0f) * 0.5f;
    return vector_add(vector_multiply(vector_create(1.0f,1.0f,1.0f), 1.0f-t),
                      vector_multiply(vector_create(0.5f,0.7f,1.0f), t));
}

static Vec g_center;
static float g_radius;
static Vec g_light;

Vec trace(Ray ray){
    Hit sh = sphere_intersect(ray, g_center, g_radius);
    float denom = ray.direction.y;
    int plane_hit = 0;
    float tp = 0.0f;
    if (fabsf(denom) > 1e-4f){
        tp = (-1.5f - ray.origin.y) / denom;
        if (tp >= 0.001f) plane_hit = 1;
    }
    Vec point, normal, material;
    int is_sphere;
    if (plane_hit && (!sh.hit || tp <= sh.t)){
        point = ray_at(ray, tp);
        normal = vector_create(0.0f, 1.0f, 0.0f);
        is_sphere = 0;
    } else if (sh.hit){
        point = sh.point;
        normal = sh.normal;
        is_sphere = 1;
    } else {
        return sky_color(ray);
    }
    Ray shadow;
    shadow.origin = vector_add(point, vector_multiply(normal, 0.001f));
    shadow.direction = g_light;
    Hit shd = sphere_intersect(shadow, g_center, g_radius);
    float brightness;
    if (shd.hit) brightness = 0.2f;
    else brightness = (float)fmax(0.0, (double)vector_dot(normal, g_light)) * 0.8f + 0.2f;
    if (is_sphere){
        return vector_create(brightness, 0.2f*brightness, 0.2f*brightness);
    } else {
        int m = (int)(floorf(point.x) + floorf(point.z));
        float checker = (m & 1) ? 0.4f : 0.9f;
        float v = checker * brightness;
        return vector_create(v, v, v);
    }
}

Vec **allocate_image(int width, int height){
    Vec **img = (Vec**)malloc(height * sizeof(Vec*));
    for (int y=0; y<height; y++) img[y] = (Vec*)malloc(width * sizeof(Vec));
    return img;
}

void free_image(Vec **img, int height){
    for (int y=0; y<height; y++) free(img[y]);
    free(img);
}

void write_image(Vec **img, const char *filename, int width, int height){
    FILE *f = fopen(filename, "w");
    if (!f){ fprintf(stderr, "Error: could not open %s\n", filename); return; }
    fprintf(f, "P3\n%d %d\n255\n", width, height);
    for (int y=0; y<height; y++){
        for (int x=0; x<width; x++){
            Vec c = img[y][x];
            int r = (int)((float)fmin(1.0, fmax(0.0, (double)c.x)) * 255.99f);
            int g = (int)((float)fmin(1.0, fmax(0.0, (double)c.y)) * 255.99f);
            int b = (int)((float)fmin(1.0, fmax(0.0, (double)c.z)) * 255.99f);
            fprintf(f, "%d %d %d\n", r, g, b);
        }
    }
    fclose(f);
    fprintf(stderr, "Wrote image to %s\n", filename);
}

int main(void){
    g_center = vector_create(0.0f, -0.5f, -5.0f);
    g_radius = 1.0f;
    g_light = vector_normalize(vector_create(1.0f, 1.0f, -1.0f));
    float aspect = (float)WIDTH / (float)HEIGHT;

    fprintf(stderr, "Creating high-resolution image: %dx%d\n", WIDTH, HEIGHT);
    fprintf(stderr, "This will be downsampled with ffmpeg after rendering\n");
    Vec **image = allocate_image(WIDTH, HEIGHT);
    fprintf(stderr, "Rendering high-resolution image...\n");

    Vec origin = vector_create(0.0f, 0.0f, 0.0f);
    for (int y=0; y<HEIGHT; y++){
        fprintf(stderr, "\rProgress: %.1f%%", (float)y * 100.0f / (float)HEIGHT);
        float fy = 1.0f - (float)y / (float)(HEIGHT-1);
        float vy2 = fy + fy;
        for (int x=0; x<WIDTH; x++){
            float dx = (float)x / (float)(WIDTH-1) * (2.0f*aspect) - aspect;
            float dy = vy2 - 1.0f;
            float dz = -1.0f;
            Ray ray;
            ray.origin = origin;
            ray.direction = vector_normalize(vector_create(dx, dy, dz));
            image[y][x] = trace(ray);
        }
    }
    fprintf(stderr, "\nRendering complete\n");
    write_image(image, "image.ppm", WIDTH, HEIGHT);
    free_image(image, HEIGHT);
    fprintf(stderr, "Done.\n");
    return 0;
}

